                        </div>
                        <div className="flex items-center">
                          <Checkbox
                            id="service-decor"
                            checked={form.getValues("additionalServices")?.includes("Décor Setup")}
                            onCheckedChange={(checked) => 
                              handleAdditionalServiceChange("Décor Setup", checked as boolean)
