              </div>

              {form.getValues("specialRequests") && (
                <div className="mt-4">
                  <p className="text-sm text-[#343a40]">Special Requests:</p>
                  <p className="font-medium">{form.getValues("specialRequests")}</p>
                </div>
              )}

              <div className="mt-4 border-t pt-4">
                <p className="text-sm text-[#343a40]">Estimated Total:</p>
                <p className="font-medium text-lg text-primary">
                  {formatPrice((services.find(s => s.id === form.getValues("serviceId"))?.basePrice || 0) * form.getValues("guestCount"))}
                </p>
                <p className="text-xs text-[#343a40]">Final pricing may vary based on menu selection and additional services</p>
              </div>
            </div>

            <div className="mb-6">
              <h4 className="font-heading font-bold text-lg mb-4">Contact Information</h4>

              <Form {...form}>
                <form className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <FormField
                        control={form.control}
                        name="name"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Full Name *</FormLabel>
                            <FormControl>
                              <Input {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="email"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Email Address *</FormLabel>
                            <FormControl>
                              <Input type="email" {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>
                    <div>
                      <FormField
                        control={form.control}
                        name="phone"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Phone Number *</FormLabel>
                            <FormControl>
                              <Input type="tel" {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="company"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Company/Organization (if applicable)</FormLabel>
                            <FormControl>
                              <Input {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>
                  </div>

                  <FormField
                    control={form.control}
                    name="termsAgreed"
                    render={({ field }) => (
                      <FormItem className="flex items-start space-x-2 space-y-0">
                        <FormControl>
                          <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel>
                            I agree to the <a href="#" className="text-primary hover:underline">terms and conditions</a> *
                          </FormLabel>
                          <FormMessage />
                        </div>
                      </FormItem>
                    )}
                  />
                </form>
              </Form>
            </div>

            <div className="bg-primary bg-opacity-10 p-4 rounded-lg mb-4">
              <p className="text-sm">
                <i className="fas fa-info-circle mr-2 text-primary"></i> 
                Your booking request will be reviewed by our team. We will contact you within 24 hours to confirm availability and discuss any details.
              </p>
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="sm:max-w-4xl p-0 overflow-hidden">
        <DialogHeader className="p-6 pb-0">
          <DialogTitle className="text-2xl font-heading font-bold text-primary">Book Your Catering Service</DialogTitle>
          <DialogDescription>
            <div className="mt-8 mb-4">
              <div className="flex items-center w-full">
                {/* Step 1 */}
                <div className="relative flex flex-col items-center text-center">
                  <div 
                    className={`flex items-center justify-center w-10 h-10 rounded-full font-medium
                      ${isStepComplete(1) 
                        ? "bg-[#2ecc71] text-white" 
                        : currentStep === 1 
                          ? "bg-primary text-white" 
                          : "bg-gray-200 text-[#343a40]"
                      }`}
                  >
                    {isStepComplete(1) ? <i className="fas fa-check"></i> : "1"}
                  </div>
                  <div className={`text-xs font-medium mt-1 ${currentStep === 1 ? "text-primary" : "text-[#343a40]"}`}>Service</div>
                </div>

                {/* Line */}
                <div className="w-full h-1 bg-gray-200 flex-grow mx-2">
                  <div className="h-1 bg-primary" style={{ width: currentStep > 1 ? "100%" : "0%" }}></div>
                </div>

                {/* Step 2 */}
                <div className="relative flex flex-col items-center text-center">
                  <div 
                    className={`flex items-center justify-center w-10 h-10 rounded-full font-medium
                      ${isStepComplete(2) 
                        ? "bg-[#2ecc71] text-white" 
                        : currentStep === 2 
                          ? "bg-primary text-white" 
                          : "bg-gray-200 text-[#343a40]"
                      }`}
                  >
                    {isStepComplete(2) ? <i className="fas fa-check"></i> : "2"}
                  </div>
                  <div className={`text-xs font-medium mt-1 ${currentStep === 2 ? "text-primary" : "text-[#343a40]"}`}>Date</div>
                </div>

                {/* Line */}
                <div className="w-full h-1 bg-gray-200 flex-grow mx-2">
                  <div className="h-1 bg-primary" style={{ width: currentStep > 2 ? "100%" : "0%" }}></div>
                </div>

                {/* Step 3 */}
                <div className="relative flex flex-col items-center text-center">
                  <div 
                    className={`flex items-center justify-center w-10 h-10 rounded-full font-medium
                      ${isStepComplete(3) 
                        ? "bg-[#2ecc71] text-white" 
                        : currentStep === 3 
                          ? "bg-primary text-white" 
                          : "bg-gray-200 text-[#343a40]"
                      }`}
                  >
                    {isStepComplete(3) ? <i className="fas fa-check"></i> : "3"}
                  </div>
                  <div className={`text-xs font-medium mt-1 ${currentStep === 3 ? "text-primary" : "text-[#343a40]"}`}>Details</div>
                </div>

                {/* Line */}
                <div className="w-full h-1 bg-gray-200 flex-grow mx-2">
                  <div className="h-1 bg-primary" style={{ width: currentStep > 3 ? "100%" : "0%" }}></div>
                </div>

                {/* Step 4 */}
                <div className="relative flex flex-col items-center text-center">
                  <div 
                    className={`flex items-center justify-center w-10 h-10 rounded-full font-medium
                      ${isStepComplete(4) 
                        ? "bg-[#2ecc71] text-white" 
                        : currentStep === 4 
                          ? "bg-primary text-white" 
                          : "bg-gray-200 text-[#343a40]"
                      }`}
                  >
                    "4"
                  </div>
                  <div className={`text-xs font-medium mt-1 ${currentStep === 4 ? "text-primary" : "text-[#343a40]"}`}>Confirm</div>
                </div>
              </div>
            </div>
          </DialogDescription>
        </DialogHeader>

        <div className="p-6 max-h-[70vh] overflow-y-auto">
          {renderStepContent()}
        </div>

        <div className="bg-gray-50 px-6 py-4 flex justify-end gap-2">
          {currentStep > 1 && (
            <Button 
              variant="outline" 
              onClick={prevStep}
            >
              Previous
            </Button>
          )}

          {currentStep < 4 ? (
            <Button 
              onClick={nextStep}
              className="bg-primary"
            >
              Next Step
            </Button>
          ) : (
            <Button 
              onClick={form.handleSubmit(onSubmit)}
              className="bg-primary"
              disabled={createBookingMutation.isPending}
            >
              {createBookingMutation.isPending ? "Submitting..." : "Submit Booking"}
            </Button>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

